@dataclass(frozen=True)
class TokiPonaWord:
    name: str
    meaning: str
    glyph_png_base64: str
    glyph_slug: str | None = None

    @property
    def glyph_key(self) -> str:
        return self.glyph_slug or self.name


DEFAULT_WORDS: tuple[TokiPonaWord, ...] = tuple(
    TokiPonaWord(name=name, meaning=meaning, glyph_png_base64=glyph_b64)
    for name, meaning, glyph_b64 in TOKI_PONA_WORDS
)


class TokiPonaData:
    """Own the built-in words, glyph map, and simple navigation."""

    glyphs = {w.name: w.glyph_png_base64 for w in DEFAULT_WORDS}
    words_table = TOKI_PONA_WORDS

    def __init__(
        self,
        words: Iterable[TokiPonaWord] | None = None,
        *,
        rng: random.Random | None = None,
    ) -> None:
        self.words = tuple(words or DEFAULT_WORDS)
        self.rng = rng or random.Random()
        self._random_cycle: list[TokiPonaWord] = []
        self.words_by_name = {word.name: word for word in self.words}
        self.index_by_name = {word.name: index for index, word in enumerate(self.words)}

        if len(self.words_by_name) != len(self.words):
            raise ValueError("duplicate toki pona word names are not allowed")

    def all(self) -> tuple[TokiPonaWord, ...]:
        return self.words

    def get(self, name: str) -> TokiPonaWord:
        word = self.words_by_name.get(name.strip().lower())
        if word is None:
            raise ValueError(f"unknown toki pona word: {name}")
        return word

    def random(self) -> TokiPonaWord:
        if not self._random_cycle:
            self._random_cycle = list(self.words)
            self.rng.shuffle(self._random_cycle)

        return self._random_cycle.pop()

    def remaining_random_cycle_names(self) -> tuple[str, ...]:
        return tuple(word.name for word in self._random_cycle)

    def restore_random_cycle(self, names: Iterable[str]) -> None:
        restored_words = [self.get(name) for name in names]

        if len(restored_words) != len({word.name for word in restored_words}):
            raise ValueError("random cycle cannot contain duplicate words")

        self._random_cycle = restored_words

    def next(self, current: TokiPonaWord | str) -> TokiPonaWord:
        return self._step(current, direction=1)

    def previous(self, current: TokiPonaWord | str) -> TokiPonaWord:
        return self._step(current, direction=-1)

    def first_starting_with(self, letter: str) -> TokiPonaWord | None:
        prefix = letter.strip().lower()
        if not prefix:
            return None

        for word in self.words:
            if word.name.startswith(prefix):
                return word
        return None

    def first_matching_meaning(self, text: str) -> TokiPonaWord | None:
        query = text.strip().lower()
        if not query:
            return None

        for word in self.words:
            if query in word.meaning.lower():
                return word
        return None

    def glyph_for(self, current: TokiPonaWord | str) -> str:
        word = self._coerce_word(current)
        return self.glyphs[word.glyph_key]

    def _step(self, current: TokiPonaWord | str, *, direction: int) -> TokiPonaWord:
        word = self._coerce_word(current)
        current_index = self.index_by_name[word.name]
        next_index = (current_index + direction) % len(self.words)
        return self.words[next_index]

    def _coerce_word(self, value: TokiPonaWord | str) -> TokiPonaWord:
        if isinstance(value, TokiPonaWord):
            return value
        return self.get(value)